/**
 * BUNDLED PLANT KNOWLEDGE (Phase 3) — light, humidity, difficulty, pet
 * toxicity, temperature and short care notes. Generated by Claude Code at
 * build time: $0, offline forever, never a runtime API call.
 *
 * Keyed by the same normalized names as profiles.ts: exact entries first,
 * then genus/type substring patterns (FIRST MATCH WINS — order is
 * load-bearing, mirroring LOCAL_PROFILE_PATTERNS). Toxicity follows ASPCA
 * guidance for cats & dogs; when a genus is mixed we err toward caution.
 */
import { normalizePlantName } from './profiles';

export type LightNeeds = 'low' | 'medium' | 'bright_indirect' | 'full_sun';
export type HumidityPref = 'low' | 'medium' | 'high';
export type Difficulty = 'easy' | 'moderate' | 'fussy';
export type PetToxicity = 'safe' | 'mild' | 'toxic';

export interface CareInfo {
  light_needs: LightNeeds;
  humidity_pref: HumidityPref;
  difficulty: Difficulty;
  pet_toxic: PetToxicity;
  temp_range: string;
  care_notes: string;
}

export const LIGHT_LABELS: Record<LightNeeds, string> = {
  low: 'Low light OK',
  medium: 'Medium light',
  bright_indirect: 'Bright indirect',
  full_sun: 'Full sun',
};

export const HUMIDITY_LABELS: Record<HumidityPref, string> = {
  low: 'Dry air OK',
  medium: 'Average humidity',
  high: 'High humidity',
};

export const DIFFICULTY_LABELS: Record<Difficulty, string> = {
  easy: 'Easy',
  moderate: 'Moderate',
  fussy: 'Fussy',
};

export const TOXIC_LABELS: Record<PetToxicity, string> = {
  safe: 'Pet safe',
  mild: 'Mildly toxic to pets',
  toxic: 'Toxic to cats & dogs',
};

function info(
  light: LightNeeds,
  humidity: HumidityPref,
  difficulty: Difficulty,
  toxic: PetToxicity,
  temp: string,
  notes: string,
): CareInfo {
  return {
    light_needs: light,
    humidity_pref: humidity,
    difficulty,
    pet_toxic: toxic,
    temp_range: temp,
    care_notes: notes,
  };
}

