/** Bundled care knowledge for a plant name, or null if unknown. */
export function careInfoLookup(name: string): CareInfo | null {
  const n = normalizePlantName(name);
  if (!n) return null;
  if (CARE_EXACT[n]) return CARE_EXACT[n];
  for (const { match, i } of CARE_PATTERNS) {
    if (n.indexOf(match) !== -1) return i;
  }
  return null;
}
